def track_job(job_name):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start = time.perf_counter()
            try:
                return func(*args, **kwargs)
            finally:
                JOB_DURATION.labels(job_name=job_name).observe(time.perf_counter() - start)
        return wrapper
    return decorator


