@app.route("/orders", methods=["POST"])
def create_order():
    payload = request.get_json(silent=True) or {}
    amount = float(payload.get("amount", random.uniform(20, 500)))
    success = bool(payload.get("success", random.choice([True, True, True, False])))

    processing_time = simulate_checkout()
    ORDER_VALUE.observe(amount)

    if success:
        ORDERS_CREATED.labels(status="success").inc()
        return jsonify(
            {
                "status": "created",
                "amount": amount,
                "processing_time_seconds": processing_time,
            }
        ), 201

    ORDERS_CREATED.labels(status="failed").inc()
    return jsonify(
        {
            "status": "failed",
            "amount": amount,
            "processing_time_seconds": processing_time,
        }
    ), 400


