@app.route("/payments/process", methods=["POST"])
def process_payment():
    payload = request.get_json(silent=True) or {}
    approved = bool(payload.get("approved", random.choice([True, True, False])))

    time.sleep(random.uniform(0.02, 0.2))

    if approved:
        PAYMENT_ATTEMPTS.labels(result="approved").inc()
        return jsonify({"payment": "approved"}), 200

    PAYMENT_ATTEMPTS.labels(result="declined").inc()
    return jsonify({"payment": "declined"}), 402


